import{_ as a,o as t,c as s,j as r,a as n,a1 as d}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"花海魔法","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/4.术法/魔法/通用魔法/3.自然派系/花海魔法.md","filePath":"4.资源分区/4.术法/魔法/通用魔法/3.自然派系/花海魔法.md"}'),o={name:"4.资源分区/4.术法/魔法/通用魔法/3.自然派系/花海魔法.md"};function b(l,e,_,i,p,c){return t(),s("div",null,[...e[0]||(e[0]=[r("h1",{id:"花海魔法",tabindex:"-1"},[n("花海魔法 "),r("a",{class:"header-anchor",href:"#花海魔法","aria-label":'Permalink to "花海魔法"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌031")])])],-1),d('<h1 id="花海魔法-1" tabindex="-1">花海魔法 <a class="header-anchor" href="#花海魔法-1" aria-label="Permalink to &quot;花海魔法&quot;">​</a></h1><p>花田魔法<br> 类型：增强技<br> 价格：C+1000<br> 派系：自然<br> 花费：6<br> 成分：动作<br> 动作：移动动作<br> 射程：半径智力*2M<br> 效果： 群体<br> 持续：一个月<br> 技能描述：花海魔法能够在指定区域内迅速催生大量的花朵，短时间内将一片荒芜之地变成绚烂多彩的花海。<br> 在指定区域内召唤出一片绚丽的花田，花田中的花卉种类为施法者所见过的指定花卉，能够瞬间将该区域装点成色彩斑斓、生机盎然的花海。<br> 在花海内战斗的单位可能会因为不忍破坏花海，导致下意识的避开花海进行攻击<br> 所有在花海内进行战斗的单位都需要进行一次dc10的意志豁免，否者会因为不忍破坏花海在攻击上受到1dp减值<br> 如果没有外力干扰，花海将持续存在1个月，大约在一个月后，可能因为各种各样的原因而消失，这可能是花枯萎了，可能是自然原因，也可能是人为破坏的原因等等<br> Ps：施法者只能召唤出自己曾经见过的花卉种类，未见过的花卉无法通过此技能创造。<br> Ps：召唤的花海皆为无支线植物</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=a(o,[["render",b]]);export{f as __pageData,m as default};
